patch:
--- a/mux_selector.v
+++ b/mux_selector.v
@@ -1,16 +1,16 @@
 module mux_selector(
   input [31:0] data_a,
   input [31:0] data_b,
   input [31:0] data_c,
   input [31:0] data_d,
   input [1:0] sel,
   output reg [31:0] mux_out
 );

-  always @(data_a or data_b or sel)
+  always @(*)
   begin
     case(sel)
       2'b00: mux_out = data_a;
       2'b01: mux_out = data_b;
       2'b10: mux_out = data_c;
       2'b11: mux_out = data_d;
       default: mux_out = 32'h0;
     endcase
   end

before_code:
